        "factor": 0.75
      }
    ],
    "stop_pct": 7.5,
    "target_pct": 20.0,
    "max_hold_days": 60
  },
  {
    "name": "minervini_breakout_volume",
    "source": "Mark Minervini, Trade Like a Stock Market Wizard, 2013",
    "principle": "Enter on a breakout from a base on expanding volume \u2014 price clears the prior 50-day high with volume above its average.",
    "conditions": [
      {
        "left": "close",
        "op": ">",
        "right": "sma_150",
        "factor": 1.0
      },
      {
        "left": "close",
