        "left": "volume",
        "op": ">",
        "right": "vol_sma_20",
        "factor": 1.5
      }
    ],
    "stop_pct": 5.0,
    "target_pct": 15.0,
    "max_hold_days": 20
  },
  {
    "name": "gujral_gap_and_hold_uptrend",
    "source": "Ashwani Gujral \u2014 How to Make Money in Intraday Trading (Vision Books, 2018)",
    "principle": "Gaps in trend direction that hold above the prior day's range tend to run; fading gaps against the bigger trend is low-probability.",
    "conditions": [
      {
        "left": "sma_20",
        "op": ">",
        "right": "sma_50",
        "factor": 1.0
      },
      {
        "left": "open",
        "op": ">",
        "right": "highest_5",
        "factor": 1.005
      },
      {
        "left": "close",
        "op": ">",
        "right": "open",
        "factor": 1.0
      },
      {
        "left": "volume",
        "op": ">",
        "right": "vol_sma_20",
        "factor": 1.0
      }
    ],
    "stop_pct": 4.0,
    "target_pct": 10.0,
    "max_hold_days": 10
  },
  {
    "name": "sadekar_bullish_engulfing_support",
    "source": "Sadekar \u2014 How to Make Money Trading with Candlestick Charts",
    "principle": "Bullish engulfing after a decline, at or near a moving-average support zone, confirmed by above-average volume, in a larger uptrend.",
    "conditions": [
      {
        "left": "close",
        "op": ">",
        "right": "sma_200",
        "factor": 1.0
      },
      {
        "left": "close",
        "op": ">",
        "right": "sma_50",
        "factor": 0.98
      },
      {
        "left": "ret_10",
        "op": "<",
        "right": 0.0,
        "factor": 1.0
      },
      {
        "left": "bullish_engulfing",
        "op": ">",
        "right": 0.5,
        "factor": 1.0
      },
      {
        "left": "volume",
        "op": ">",
        "right": "vol_sma_20",
        "factor": 1.2
      }
    ],
    "stop_pct": 4.0,
    "target_pct": 10.0,
    "max_hold_days": 20
  },
  {
    "name": "sadekar_hammer_confirmation",
    "source": "Sadekar \u2014 How to Make Money Trading with Candlestick Charts",
    "principle": "Hammer after a decline; buy on the follow-through candle closing above the hammer's high, not on the hammer itself.",
    "conditions": [
      {
        "left": "ret_10",
        "op": "<",
        "right": 0.0,
        "factor": 1.0
      },
      {
        "left": "hammer",
        "op": ">",
