      {
        "left": "close",
        "op": ">",
        "right": "sma_50",
        "factor": 0.97
      }
    ],
    "stop_pct": 5.0,
    "target_pct": 10.0,
    "max_hold_days": 15
  },
  {
    "name": "sadekar_strong_close_volume",
    "source": "Sadekar \u2014 How to Make Money Trading with Candlestick Charts",
    "principle": "Strong close in the top of the day's range on expanding volume marks institutional demand; acts as a continuation entry in an uptrend.",
    "conditions": [
      {
        "left": "close",
        "op": ">",
        "right": "sma_50",
        "factor": 1.0
