        "right": 0.0,
        "factor": 1.0
      }
    ],
    "stop_pct": 4.0,
    "target_pct": 10.0,
    "max_hold_days": 20
  },
  {
    "name": "sadekar_inside_day_breakout_uptrend",
    "source": "Sadekar \u2014 How to Make Money Trading with Candlestick Charts",
    "principle": "Inside-day (harami) resolution: a quiet inside candle after a big move, resolved by a close beyond the inside candle's range in the trend direction.",
    "conditions": [
      {
        "left": "close",
        "op": ">",
        "right": "sma_50",
        "factor": 1.0
      },
      {
        "left": "ret_10",
        "op": ">",
        "right": 0.0,
