        "right": "vol_sma_20",
        "factor": 1.0
      }
    ],
    "stop_pct": 3.0,
    "target_pct": 8.0,
    "max_hold_days": 15
  },
  {
    "name": "turner_trend_breakout_volume",
    "source": "Turner, A Beginner's Guide to Day Trading Online, 2nd ed. 2007",
    "principle": "Breakouts count only when volume expands versus recent average; buy strength that clears a recent consolidation high.",
    "conditions": [
      {
        "left": "close",
        "op": ">",
        "right": "highest_20",
        "factor": 1.0
      },
      {
        "left": "volume",
        "op": ">",
        "right": "vol_sma_20",
        "factor": 1.3
      }
    ],
    "stop_pct": 5.0,
    "target_pct": 10.0,
    "max_hold_days": 15
  },
  {
    "name": "turner_trend_filter_sma",
    "source": "Turner, A Beginner's Guide to Day Trading Online, 2nd ed. 2007",
    "principle": "Avoid the chop: stand aside when moving averages are flat and ranges are narrow. Trade only when price is above a rising average and range is not compressed.",
    "conditions": [
      {
        "left": "close",
        "op": ">",
        "right": "sma_50",
        "factor": 1.0
      },
      {
        "left": "sma_20",
        "op": ">",
        "right": "sma_50",
        "factor": 1.0
      },
      {
        "left": "range_ratio_5",
        "op": ">",
        "right": 1.0,
        "factor": 1.0
      }
    ],
    "stop_pct": 5.0,
    "target_pct": 10.0,
    "max_hold_days": 15
  },
  {
    "name": "schwager_trend_with_pullback_strength",
    "source": "Stock Market Wizards \u2014 Schwager synthesis, Ryan/Minervini",
    "principle": "Wait for the exact setup: a trending stock that pauses briefly and resumes strength before entering \u2014 patience over action.",
    "conditions": [
      {
        "left": "close",
        "op": ">",
        "right": "sma_200",
        "factor": 1.0
      },
      {
        "left": "sma_50",
        "op": ">",
